import torch, torch.nn as nn
import torchvision.models as models

def gram_matrix(feat: torch.Tensor) -> torch.Tensor:
    """Compute Gram matrix for style loss: G_ij = sum_k F_ik * F_jk / (C*H*W)."""
    b, c, h, w = feat.size()
    F = feat.view(b, c, h * w)
    return torch.bmm(F, F.transpose(1, 2)) / (c * h * w)


class VGGStyleExtractor(nn.Module):
    """Extract activations from VGG-16 conv layers for style transfer."""
    STYLE_LAYERS   = ["0", "5", "10", "19"]   # relu1_2, relu2_2, relu3_3, relu4_3
    CONTENT_LAYERS = ["19"]                    # relu4_3

    def __init__(self):
        super().__init__()
        vgg = models.vgg16(weights=models.VGG16_Weights.IMAGENET1K_V1).features
        self.layers = nn.ModuleDict({str(i): vgg[i] for i in range(28)})
        for p in self.parameters():
            p.requires_grad = False

    def forward(self, x):
        style_feats, content_feats = {}, {}
        for i, (name, layer) in enumerate(self.layers.items()):
            x = layer(x)
            if name in self.STYLE_LAYERS:
                style_feats[name] = gram_matrix(x)
            if name in self.CONTENT_LAYERS:
                content_feats[name] = x
        return style_feats, content_feats


extractor = VGGStyleExtractor()
dummy = torch.randn(1, 3, 224, 224)
sf, cf = extractor(dummy)
print("Style Gram shapes:", {k: v.shape for k, v in sf.items()})
print("Content feat shape:", {k: v.shape for k, v in cf.items()})
